hardsigmoid_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

// Helper function to compute linear thread index safely
__device__ __inline__ int get_linear_thread_id() {
    return threadIdx.x + blockIdx.x * blockDim.x;
}

// Helper function to compute grid stride safely
__device__ __inline__ int get_grid_stride() {
    return blockDim.x * gridDim.x;
}

// Vectorized kernel using float4 with robust bounds checking
__global__ void hardsigmoid_kernel_vectorized(const float* __restrict__ input, 
                                              float* __restrict__ output, 
                                              int size) {
    // Runtime assertion for expected 1D configuration
    assert(blockDim.y == 1 && blockDim.z == 1);
    assert(gridDim.y == 1 && gridDim.z == 1);

    // Calculate starting index with proper bounds checking
    const int start_idx = blockIdx.x * blockDim.x * 4 + threadIdx.x * 4;

    // Process vectorized elements if within bounds
    if (start_idx + 3 < size) {
        // Safe load with alignment check
        if ((reinterpret_cast<size_t>(&input[start_idx]) & 0xF) == 0) {
            float4 in_vec = *reinterpret_cast<const float4*>(&input[start_idx]);
            float4 out_vec;

            const float one_sixth = 1.0f / 6.0f;
            const float half = 0.5f;

            out_vec.x = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.x, one_sixth, half)));
            out_vec.y = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.y, one_sixth, half)));
            out_vec.z = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.z, one_sixth, half)));
            out_vec.w = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(in_vec.w, one_sixth, half)));

            // Safe store with alignment check
            if ((reinterpret_cast<size_t>(&output[start_idx]) & 0xF) == 0) {
                *reinterpret_cast<float4*>(&output[start_idx]) = out_vec;
            } else {
                // Fallback to scalar store if unaligned
                output[start_idx] = out_vec.x;
                output[start_idx + 1] = out_vec.y;
                output[start_idx + 2] = out_vec.z;
                output[start_idx + 3] = out_vec.w;
            }
        } else {
            // Fallback to scalar load if unaligned
            for (int i = 0; i < 4; i++) {
                int elem_idx = start_idx + i;
                if (elem_idx < size) {
                    float val = input[elem_idx];
                    output[elem_idx] = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(val, 1.0f/6.0f, 0.5f)));
                }
            }
        }
    }

    // Handle remaining elements using grid-stride loop (prevents redundant work)
    int remaining_start = start_idx + 4;
    if (remaining_start < size) {
        int stride = get_grid_stride() * 4;
        for (int idx = remaining_start; idx < size; idx += stride) {
            float val = input[idx];
            output[idx] = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(val, 1.0f/6.0f, 0.5f)));
        }
    }
}

// Robust scalar kernel with proper grid-stride loop
__global__ void hardsigmoid_kernel_scalar(const float* __restrict__ input, 
                                          float* __restrict__ output, 
                                          int size) {
    // Runtime assertion for expected 1D configuration
    assert(blockDim.y == 1 && blockDim.z == 1);
    assert(gridDim.y == 1 && gridDim.z == 1);

    // Use linear thread ID and grid stride for robust work distribution
    int tid = get_linear_thread_id();
    int stride = get_grid_stride();

    for (int i = tid; i < size; i += stride) {
        float val = input[i];
        output[i] = fmaxf(0.0f, fminf(1.0f, __fmaf_rd(val, 1.0f/6.0f, 0.5f)));
    }
}

torch::Tensor hardsigmoid_cuda_optimized(torch::Tensor input) {
    auto size = input.numel();
    auto output = torch::empty_like(input);

    if (size == 0) {
        return output;
    }

    // Use optimal configuration with safety margins
    if (size >= 1024) {
        const int block_size = 256;
        int num_blocks = (size + (block_size * 4) - 1) / (block_size * 4);

        // Ensure reasonable grid size with upper and lower bounds
        num_blocks = min(max(num_blocks, 32), 1024);

        // Verify launch configuration
        assert(num_blocks <= 1024 && block_size <= 1024);

        hardsigmoid_kernel_vectorized<<<num_blocks, block_size>>>(
            input.data_ptr<float>(),
            output.data_ptr<float>(),
            size
        );
    } else {
        const int block_size = min(256, size);
        int num_blocks = (size + block_size - 1) / block_size;
        num_blocks = min(max(num_blocks, 1), 1024);

        // Verify launch configuration
        assert(num_blocks <= 1024 && block_size <= 1024);

        hardsigmoid_kernel_scalar<<<num_blocks, block_size>>>(
            input.data_ptr<float>(),
            output.data_ptr<float>(),
            size
        );
    }

    return output;
}
